    private int value;
    synchronized void inc() { value++; }
    synchronized int get() { return value; }
  }
- C) YANLIS: Threadler stack ve heapi tum processlerle global paylasir.
  Neden yanlis: Process izolasyonu nedeniyle thread bellegi tum processlere global acik degildir.
