    private int value;
    synchronized void inc() { value++; }
    synchronized int get() { return value; }
  }
- D) YANLIS: Threadler yalnizca CPU registerlarini paylasir.
  Neden yanlis: Paylasim yalnizca register seviyesinde degildir; esas paylasilan alan process heapidir.
  Dogrusu: 'Ayni process icindeki threadler heapi paylasir, stackleri ayridir.'
